-- Culbridge Shipment Schema (Phase 1 - LabResult[] Migration)\n-- Added lab_results_array JSON for structured LabResult[]\n-- Legacy lab_results TEXT deprecated for Phase 2 removal\n\n-- Shipments table - Core entity\nCREATE TABLE IF NOT EXISTS Shipments (\n    id VARCHAR(50) PRIMARY KEY,\n    \n    -- Status\n    status VARCHAR(20) DEFAULT 'DRAFT' \n        CHECK (status IN ('DRAFT', 'PARTIAL', 'VALIDATING', 'READY', 'SUBMITTED', 'UNDER_REVIEW', 'APPROVED', 'REJECTED')),\n    \n    -- Commodity\n    commodity_data JSON,\n    category VARCHAR(50),\n    \n    -- Entity\n    exporter_id VARCHAR(50),\n    \n    -- Destination\n    destination_data JSON,\n    \n    -- PHASE 1: Structured Lab Results (LabResult[])\n    lab_results_array JSON,  -- NEW: Array of {testType, result, value?, unit?, accredited, labName?, testDate}\n    \n    -- LEGACY (DEPRECATED - Phase 2 removal)\n    lab_results TEXT,  -- Flat object {hazard:value} - migrate to array\n    \n    -- Compliance\n    compliance_status VARCHAR(20) DEFAULT 'PASS'\n        CHECK (compliance_status IN ('PASS', 'WARNING', 'BLOCKER')),\n\n    submission_ready INTEGER DEFAULT 0,\n    evaluation_errors JSON,\n    \n    -- EUDR\n    eudr_compliant INTEGER DEFAULT 0,\n    \n    -- Timestamps\n    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n    updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n    last_evaluated_at DATETIME,\n    submitted_at DATETIME,\n    \n    FOREIGN KEY (exporter_id) REFERENCES Entities(id),\n    \n    -- PHASE 1 INDEXES\n    INDEX idx_lab_results (lab_results_array),\n    INDEX idx_status (status),\n    INDEX idx_exporter (exporter_id),\n    INDEX idx_updated (updated_at),\n    INDEX idx_submitted (submitted_at)\n);\n\n-- Rest unchanged...\n-- [existing document/submission tables unchanged]
